protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    // HasIndex throws at startup in EF Core 9 Cosmos — manage indexing
    // via the container's indexing policy in Azure Portal / Bicep / Terraform.

    modelBuilder.Entity<Product>(entity =>
    {
        entity.ToContainer("Products");

        // EF Core 9 renamed the default discriminator from "Discriminator" to "$type".
        // Preserve "Discriminator" so existing 500K documents remain queryable and
        // direct SQL queries referencing c.Discriminator continue to work.
        entity.HasDiscriminator<string>("Discriminator");

        // EF Core 9 changed id generation from "Product|123" to just "123".
        // Preserve the old compound format so FindAsync / point-reads still
        // resolve existing documents and new writes stay consistent.
        entity.HasRootDiscriminatorInJsonId(true);
    });
}

